#include <stdio.h>
#include <math.h>

int mux_nto1(int inputs[], int n_inputs, int select[]) {
    int select_value = 0;
    int n_select = log2(n_inputs);

    // Convert binary select array to integer
    for (int i = 0; i < n_select; i++) {
        select_value = (select_value << 1) | select[i];
    }

    return inputs[select_value];
}

int main() {
    int inputs[] = {0, 1, 0, 1, 1, 0, 0, 1};  // 8 inputs
    int select[] = {1, 0, 1};  // Select = 5 (binary 101)

    int output = mux_nto1(inputs, 8, select);
    printf("Output: %d\n", output);  // Output: 0

    return 0;
}

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity mux_4to1 is
    Port ( I : in STD_LOGIC_VECTOR(3 downto 0);  -- I3,I2,I1,I0
           S : in STD_LOGIC_VECTOR(1 downto 0);  -- S1,S0
           Y : out STD_LOGIC);
end mux_4to1;

architecture Behavioral of mux_4to1 is
begin
    process(I, S)
    begin
        case S is
            when "00" => Y <= I(0);
            when "01" => Y <= I(1);
            when "10" => Y <= I(2);
            when "11" => Y <= I(3);
            when others => Y <= '0';
        end case;
    end process;
end Behavioral;
